-- Migration 012: subjective_problems 플래시카드 100개 초기화
-- Date: 2026-06-11
-- Purpose: 이론탭 플래시카드를 2~3줄 상세 지문 + 빈칸(_____) 형식으로 재구성
-- 분배: 7과목 × 14개 = 98개 + 2개 추가 = 100개

-- 기존 데이터 삭제
DELETE FROM subjective_problems;

-- question_text 컬럼 확인 (migration 010에서 추가됨)
ALTER TABLE subjective_problems ADD COLUMN IF NOT EXISTS question_text varchar(3000);

-- ============================================
-- 운영체제 (14개)
-- ============================================
INSERT INTO subjective_problems (subject_id, question, question_text, answer, explanation, option1, option2, option3, option4, option5, difficulty, is_ai_generated) VALUES
(1, '프로세스와 스레드의 차이', '프로세스는 운영체제로부터 _____을(를) 할당받는 독립적인 실행 단위이다.\n반면 스레드는 프로세스 내에서 _____을(를) 공유하며 실행되는 흐름이다.', '자원', '프로세스는 메모리, 파일 등 자원을 독립적으로 할당받지만, 스레드는 코드/데이터/힙 영역을 공유하고 스택만 독립적으로 가진다.', '자원', '메모리', '코드', '스택', '힙', 2, true),

(1, 'CPU 스케줄링 알고리즘', '선점형 스케줄링 알고리즘 중 _____은(는) 가장 짧은 작업을 먼저 실행하는 방식이다.\n비선점형 _____과(와) 비교하면 평균 대기 시간이 짧다는 장점이 있다.', 'SJF', 'SJF(Shortest Job First)는 다음에 도착할 프로세스의 작업 시간이 가장 짧은 것을 선택한다. 비선점형 SJF와 선점형 SRT(Shortest Remaining Time)로 나뉜다.', 'SJF', 'FIFO', 'RR', 'Priority', 'MLFQ', 2, true),

(1, '데드락 발생 조건', '데드락 발생을 위한 4가지 필요조건은 상호배제, _____, 점유와 대기, 순환대기이다.\n이 중 _____ 조건은 자원의 선점을 허용함으로써 해결할 수 있다.', '비선점', 'Coffman의 4가지 조건 중 비선점 조건은 프로세스가 자원을 얻은 후 다른 프로세스가 그 자원을 빼앗지 못하는 것을 의미한다.', '비선점', '상호배제', '점유와대기', '순환대기', '기아', 3, true),

(1, '가상 메모리 기법', '_____은(는) 프로그램의 일부분만 메모리에 적재하여 전체가 메모리에 있는 것처럼 실행하는 기법이다.\n_____을(를) 사용하면 메모리 용량보다 큰 프로그램을 실행할 수 있다.', '가상 메모리', '가상 메모리는 요청 페이징(request paging) 기법을 기반으로 하며, 필요한 페이지를 디스크에서 메모리로 가져온다.', '가상 메모리', '페이징', '세그먼테이션', '스왑핑', '단편화', 2, true),

(1, '페이지 교체 알고리즘', '_____ 알고리즘은 가장 오랫동안 사용되지 않은 페이지를 교체하는 방식이다.\n이 알고리즘은 _____ 스택을 사용하여 구현할 수 있다.', 'LRU', 'LRU(Least Recently Used)는 최근에 사용되지 않은 페이지를 교체하며, 스택이나 카운터를 통해 구현한다.', 'LRU', 'FIFO', 'OPT', 'LFU', 'NRU', 2, true),

(1, '프로세스 상태 전이', '프로세스가 _____ 상태에 있다는 것은 CPU를 할당받아 명령어를 실행 중임을 의미한다.\n이 상태에서 I/O 요청이 발생하면 _____ 상태로 전이된다.', '실행', '실행(Running) 상태에서 입출력 요구나 이벤트 대기 시 대기(Waiting/Blocked) 상태로 전환된다.', '실행', '준비', '대기', '종료', '신생', 1, true),

(1, '세마포어와 뮤텍스', '_____은(는) 이진 신호량으로 한 번에 하나의 프로세스만 임계 영역에 진입할 수 있게 한다.\n_____은(는) 소유한 스레드만 해제할 수 있는 반면, 세마포어는 다른 스레드도 해제 가능하다.', '뮤텍스', '뮤텍스(Mutex)는 상호배제를 위한 동기화 도구로, Lock/Unlock 연산을 제공한다. 소유권 개념이 있어 Lock을 건 스레드만 Unlock 가능하다.', '뮤텍스', '세마포어', '모니터', '이벤트', '조건변수', 3, true),

(1, '디스크 스케줄링', '_____ 알고리즘은 디스크 헤드가 한쪽 끝에서 반대쪽 끝까지 이동하며 이동 경로상의 모든 요청을 처리한다.\n헤드가 끝까지 이동한 후 반대 방향으로 다시 이동한다.', 'SCAN', 'SCAN(엘리베이터) 알고리즘은 헤드가 이동하며 요청을 처리하고, 끝에 도달하면 방향을 바꿔 되돌아온다. C-SCAN은 돌아올 때 처리하지 않는다.', 'SCAN', 'SSTF', 'FCFS', 'C-SCAN', 'LOOK', 2, true),

(1, '프로세스 동기화', '임계 영역(Critical Section)에 동시에 진입하는 것을 막기 위해 _____을(를) 사용한다.\n임계 영역의 3가지 만족 조건은 상호배제, 진행, 유한대기이다.', '상호배제', '임계 영역은 공유 데이터를 접근하는 코드 영역으로, 한 번에 하나의 프로세스만 진입해야 한다. 이를 보장하는 것이 상호배제이다.', '상호배제', '동기화', '세마포어', '뮤텍스', '모니터', 2, true),

(1, '캐시 메모리', 'CPU와 주기억장치 사이의 속도 차이를 보완하기 위해 _____을(를) 사용한다.\n이 메모리는 접근 속도가 매우 빠르지만 용량이 작고 가격도 비싸다.', '캐시 메모리', '캐시 메모리는 SRAM으로 구성되며, CPU 레지스터와 주기억장치 사이에 위치하여 자주 사용하는 데이터를 저장한다.', '캐시 메모리', '버퍼 메모리', '보조 기억장치', '가상 메모리', '플래시 메모리', 1, true),

(1, '파일 시스템', '파일의 물리적 할당 방식 중 _____ 할당은 파일의 각 블록이 불연속적으로 분산되어 저장되며, 각 블록에 다음 블록의 주소를 포인터로 저장한다.', '연결', '연결 할당은 각 블록에 다음 블록의 주소가 포함되어 있어 순차 접근에 적합하지만, 직접 접근은 불가능하다. FAT과 유사하다.', '연결', '연속', '색인', '해시', 'B-트리', 2, true),

(1, '인터럽트 처리', '하드웨어 장치가 CPU에게 이벤트 발생을 알리기 위해 사용하는 신호를 _____이라고 한다.\n이 신호를 받으면 CPU는 현재 작업을 중단하고 _____ 처리 루틴을 실행한다.', '인터럽트', '인터럽트는 I/O 완료, 예외 상황 등을 CPU에 알리는 비동기 신호로, 인터럽트 서비스 루틴(ISR)이 처리한다.', '인터럽트', '폴링', 'DMA', '버스', '클록', 2, true),

(1, '메모리 단편화', '메모리 할당과 해제를 반복하면 작은 빈 메모리 조각들이 흩어지는 현상이 발생하는데, 이를 _____이라고 한다.\n이 문제를 해결하기 위해 _____ 기법을 사용한다.', '단편화', '단편화(Fragmentation)는 외부 단편화와 내부 단편화로 나뉜다. 압축(Compaction)으로 외부 단편화를 해결할 수 있다.', '단편화', '페이징', '스왑핑', '세그먼테이션', '가상화', 2, true),

(1, '스케줄러 종류', '장기 스케줄러는 _____ 스케줄러라고도 하며, 메모리에 어떤 프로세스를 올릴지 결정한다.\n단기 스케줄러는 _____ 스케줄러라고 하며, CPU를 어떤 프로세스에게 줄지 결정한다.', '작업', '장기 스케줄러(Job Scheduler)는 Degree of Multiprogramming을 제어하고, 단기 스케줄러(CPU Scheduler)는 실행할 프로세스를 선택한다.', '작업', 'CPU', '중기', '입출력', '디스크', 2, true);

-- ============================================
-- 네트워크 (14개)
-- ============================================
INSERT INTO subjective_problems (subject_id, question, question_text, answer, explanation, option1, option2, option3, option4, option5, difficulty, is_ai_generated) VALUES
(2, 'OSI 7계층 모델', 'OSI 참조 모델의 계층을 아래부터 나열하면 물리, 데이터링크, 네트워크, 전송, 세션, 표현, _____ 이다.\n가장 상위 계층인 _____ 은(는) 사용자와 직접 상호작용한다.', '응용', 'OSI 7계층은 Application, Presentation, Session, Transport, Network, Data Link, Physical 순이다. 응용 계층이 최상위이다.', '응용', '세션', '전송', '네트워크', '표현', 1, true),

(2, 'TCP/IP 4계층', 'TCP/IP 모델의 계층은 네트워크 접근, 인터넷, 전송, _____ 이다.\n이 중 인터넷 계층의 주요 프로토콜은 _____ 이다.', '응용', 'TCP/IP의 인터넷 계층은 IP, ICMP, ARP 등을 포함하며, 경로 선택과 패징 전달을 담당한다. 응용 계층이 최상위이다.', '응용', '전송', '네트워크 접근', '데이터링크', '물리', 1, true),

(2, 'IP 주소 체계', 'IPv4 주소는 _____ 비트로 구성되어 있으며, 클래스 C의 기본 서브넷 마스크는 _____ 이다.\n클래스 C는 약 200만 개의 네트워크를 지원할 수 있다.', '32', 'IPv4는 32비트 주소 체계로 총 약 43억 개의 주소를 제공한다. 클래스 C는 110으로 시작하며, 255.255.255.0이 기본 마스크이다.', '32', '64', '128', '16', '48', 2, true),

(2, 'TCP 3-way Handshake', 'TCP 연결 설정 과정인 3-way handshake는 _____ → SYN-ACK → ACK 순으로 진행된다.\n이 과정에서 양쪽 모두 초기_____을(를) 교환하여 동기화한다.', 'SYN', 'SYN(동기화) 세그먼트로 시작하여, 서버가 SYN-ACK로 응답하고, 클라이언트가 ACK로 확인한다. 이 과정에서 Sequence Number를 교환한다.', 'SYN', 'ACK', 'FIN', 'RST', 'PSH', 2, true),

(2, '서브네팅', 'IP 주소 192.168.1.100/26에서 서브넷 마스크는 _____ 이며, 사용 가능한 호스트 수는 _____ 개이다.\n/26은 6비트를 호스트 ID로 사용한다.', '255.255.255.192', '/26은 상위 26비트를 네트워크로 사용하며, 서브넷 마스크는 255.255.255.192이다. 호스트 수는 2^6 - 2 = 62개이다.', '255.255.255.192', '255.255.255.128', '255.255.255.224', '255.255.255.240', '255.255.255.252', 3, true),

(2, '라우팅 프로토콜', '외부 게이트웨이 프로토콜인 _____은(는) 경로 벡터 프로토콜로, AS 간 라우팅에 사용된다.\n인터넷의 백본 라우팅에 널리 사용되는 프로토콜은 _____ 이다.', 'BGP', 'BGP(Border Gateway Protocol)는 AS 간 경로 정보를 교환하며, 정책 기반 라우팅을 지원한다. 인터넷의 핵심 라우팅 프로토콜이다.', 'BGP', 'OSPF', 'RIP', 'EIGRP', 'IS-IS', 3, true),

(2, 'ARP와 RARP', 'IP 주소를 물리 주소(MAC)로 변환하는 프로토콜은 _____ 이다.\n반대로 물리 주소를 IP 주소로 변환하는 것은 _____ 이다.', 'ARP', 'ARP(Address Resolution Protocol)는 IP → MAC 변환에 사용되며, RARP는 그 반대이다. DHCP도 MAC → IP 할당에 사용된다.', 'ARP', 'RARP', 'ICMP', 'IGMP', 'DHCP', 1, true),

(2, 'TCP와 UDP 차이', '신뢰성 있는 데이터 전송을 제공하는 프로토콜은 _____ 이다.\n이 프로토콜은 흐름 제어, 오류 제어, 혼잡 제어를 지원한다.', 'TCP', 'TCP는 연결형, 신뢰성 보장, 순서대로 전달, 흐름/혼잡 제어를 제공한다. UDP는 비연결형, 신뢰성 없음, 빠른 전송을 제공한다.', 'TCP', 'UDP', 'IP', 'ICMP', 'ARP', 1, true),

(2, 'HTTP와 HTTPS', '웹 브라우저와 서버 간 통신에 사용되는 프로토콜은 _____ 이다.\n보안을 강화한 _____ 은(는) SSL/TLS 암호화를 사용한다.', 'HTTP', 'HTTP는 포트 80을 사용하며 텍스트로 전송된다. HTTPS는 포트 443을 사용하며 SSL/TLS로 암호화하여 안전한 통신을 제공한다.', 'HTTP', 'HTTPS', 'FTP', 'SMTP', 'POP3', 1, true),

(2, 'DNS 시스템', '도메인 이름을 IP 주소로 변환하는 서비스는 _____ 이다.\n이 시스템은 계층적 구조로 루트, TLD, _____ 서버로 구성된다.', 'DNS', 'DNS(Domain Name System)는 계층적 데이터베이스로, www.example.com을 IP 주소로 변환한다.权威(권위) 서버가 최종 응답한다.', 'DNS', 'DHCP', 'ARP', 'WINS', 'NIS', 2, true),

(2, 'NAT 기술', '사설 네트워크의 IP 주소를 공인 IP 주소로 변환하는 기술은 _____ 이다.\n이 기술을 사용하면 하나의 공인 IP로 여러 대의 호스트가 인터넷에 접속할 수 있다.', 'NAT', 'NAT(Network Address Translation)는 사설 IP(10.x.x.x, 172.16-31.x.x, 192.168.x.x)를 공인 IP로 변환한다. NAPT는 포트도 변환한다.', 'NAT', 'PAT', 'DHCP', 'ARP', '프록시', 2, true),

(2, 'VLAN', '물리적으로 분리되지 않은 스위치에서 논리적으로Broadcast Domain을 분리하는 기술은 _____ 이다.\n이 기술은 IEEE _____ 표준을 사용한다.', 'VLAN', 'VLAN(Virtual LAN)은 스위치 포트를 논리적으로 그룹화하여 Broadcast Domain을 분리한다. IEEE 802.1Q 태그를 사용한다.', 'VLAN', 'STP', 'LACP', 'VTP', 'MSTP', 3, true),

(2, 'CSMA/CD', '이더넷에서 매체 접근 제어 방식으로 사용하는 _____ 은(는) 충돌 감지 방식이다.\n데이터 전송 중 충돌이 감지되면 _____ 신호를 보낸다.', 'CSMA/CD', 'CSMA/CD(CS with Collision Detection)는 전송 전 매체 감지, 충돌 시 JAM 신호 전송, 랜덤 백오프 후 재시도한다.', 'CSMA/CD', 'CSMA/CA', 'Token Passing', 'TDMA', 'FDMA', 2, true),

(2, 'IPv6 주소', 'IPv6 주소는 _____ 비트로 구성되어 있으며, 축약 표기법에서 연속된 0 그룹은 _____ 로 표시할 수 있다.', '128', 'IPv6는 128비트 주소로 약 3.4×10^38개의 주소를 제공한다. ::로 연속된 0 그룹을 한 번만 축약할 수 있다.', '128', '32', '64', '256', '48', 2, true);

-- ============================================
-- 데이터베이스 (15개)
-- ============================================
INSERT INTO subjective_problems (subject_id, question, question_text, answer, explanation, option1, option2, option3, option4, option5, difficulty, is_ai_generated) VALUES
(3, '정규화 이론', '제1정규형(1NF)은 모든 속성이 _____ 이어야 한다는 조건이다.\n제2정규형(2NF)은 1NF를 만족하면서 _____ 종속이 없어야 한다.', '원자값', '1NF는 도메인이 원자값으로만 구성되어야 한다. 2NF는 완전 함수적 종속을 만족해야 하며, 부분 종속을 제거한다.', '원자값', '고윳값', 'NULL값', '기본키', '외래키', 2, true),

(3, 'ER 모델', 'ER 다이어그램에서 사각형은 _____ 을(를) 나타낸다.\n다이아몬드는 _____ 를 나타내며, 타원은 속성을 나타낸다.', '엔티티', 'ER 모델에서 엔티티(사각형)는 실체, 속성(타원)은 특성, 관계(다이아몬드)는 엔티티 간 연관성을 표현한다.', '엔티티', '속성', '관계', '키', '약 엔티티', 1, true),

(3, 'SQL JOIN', '두 테이블의 모든 행을 반환하는 JOIN은 _____ 이다.\n이 JOIN은 매칭되지 않는 행도 NULL로 포함하여 반환한다.', 'FULL OUTER JOIN', 'FULL OUTER JOIN은 LEFT JOIN과 RIGHT JOIN의 합집합이다. 매칭되지 않는 쪽은 NULL로 채워진다.', 'FULL OUTER JOIN', 'INNER JOIN', 'LEFT JOIN', 'RIGHT JOIN', 'CROSS JOIN', 2, true),

(3, '트랜잭션 성질', '트랜잭션의 4가지 성질(ACID) 중 _____ 은(는) 모든 연산이 모두 성공하거나 모두 실패해야 함을 의미한다.\n원자성이라고도 불리는 이 성질은 _____ 에 의해 보장된다.', '원자성', 'ACID는 원자성(Atomicity), 일관성(Consistency), 고립성(Isolation), 지속성(Durability)이다. Rollback으로 원자성을 보장한다.', '원자성', '일관성', '고립성', '지속성', '직렬화', 2, true),

(3, '인덱스 구조', 'B+ 트리 인덱스에서 리프 노드는 실제 데이터의 _____ 을(를) 가진다.\n모든 리프 노드는 _____ 로 연결되어 순차 접근을 지원한다.', '키값', 'B+ 트리는 내부 노드에 키만 저장하고, 리프 노드에 실제 데이터 포인터를 가진다. 리프 노드 간 링크로 순차 탐색이 빠르다.', '키값', '레코드', '포인터', '주소', '페이지', 3, true),

(3, '관계 대수', '관계 대수에서 특정 컬럼만 선택하는 연산을 _____ 이라고 한다.\n이 연산 기호는 그리스 문자 _____ 이다.', '투영(Projection)', '투영(Projection, π)은 릴레이션에서 속성(열)을 선택하는 연산이다. 선택(Selection, σ)은 튜플(행)을 선택한다.', '투영(Projection)', '선택(Selection)', '결합(Join)', '합집합(Union)', '차집합(Difference)', 2, true),

(3, '무결성 제약조건', '기본키(Primary Key)는 NULL 값을 허용하지 않으며 _____ 을(를) 가져야 한다.\n이를 _____ 무결성이라고 한다.', '고유성', '개체 무결성(Entity Integrity)은 기본키가 NULL이거나 중복될 수 없다는 규칙이다. 참조 무결성은 외래키 관련 규칙이다.', '고유성', '중복성', '연결성', '참조성', '도메인', 2, true),

(3, '스키마 변환', '개념 스키마를 외부 스키마로 변환하는 것을 _____ 이라고 한다.\n이 과정은 특정 사용자 관점에 맞는 _____ 을(를) 만드는 것이다.', '뷰 정의', '외부 스키마(뷰)는 개념 스키마의 일부만 추출하거나 재구성한 것으로, CREATE VIEW 문으로 정의한다.', '뷰 정의', '논리 설계', '물리 설계', '정규화', '역정규화', 2, true),

(3, '데이터베이스 언어', '데이터를 정의하는 언어는 _____ 이다.\nCREATE, ALTER, DROP 명령어가 이에 속한다.', 'DDL', 'DDL(Data Definition Language)은 스키마 정의에 사용된다. DML은 데이터 조작(SELECT, INSERT, UPDATE, DELETE), DCL은 권한 관리이다.', 'DDL', 'DML', 'DCL', 'DQL', 'TCL', 1, true),

(3, '함수적 종속', '속성 X가 속성 Y를 함수적으로 결정하면 X → Y로 표기한다.\n이때 X를 _____ 라고 하며, Y는 X에 종속되어 있다.', '결정자(Determinant)', '함수적 종속에서 좌변을 결정자(Determinant)라고 한다. 완전 함수적 종속은 진부분 집합이 결정할 수 없는 경우이다.', '결정자(Determinant)', '후보키', '기본키', '외래키', '대체키', 3, true),

(3, '이상 현상', '정규화를 하지 않은 릴레이션에서 발생하는 문제점을 _____ 라고 한다.\n삽입 이상, 삭제 이상, _____ 이상으로 나뉜다.', '이상(Anomaly)', '갱신 이상은 같은 데이터가 여러 곳에 중복 저장되어 일부만 수정되는 경우이다. 정규화로 중복을 제거하여 해결한다.', '이상(Anomaly)', '중복', '손실', '분리', '결합', 2, true),

(3, '병행 제어', '여러 트랜잭션이 동시에 실행될 때 데이터 일관성을 보장하기 위한 기법을 _____ 이라고 한다.\n락(Lock), _____, 타임스탬프 등의 방법이 있다.', '병행 제어', '병행 제어(Concurrency Control)는 직렬화 가능성을 보장한다. 2PL(2-Phase Locking)이 대표적인 방법이다.', '병행 제어', '복구', '무결성', '보안', '백업', 2, true),

(3, '데이터 웨어하우스', '분석을 위해 여러 소스의 데이터를 통합하여 저장하는 시스템을 _____ 라고 한다.\n이 시스템의 4가지 특징은 주제 중심, 통합, _____, 비휘발성이다.', '데이터 웨어하우스', '데이터 웨어하우스는 시계열 데이터를 포함하며, 의사결정 지원(DSS)에 사용된다. ETL 과정으로 데이터를 적재한다.', '데이터 웨어하우스', '데이터 마트', 'OLTP', '데이터베이스', '캐시', 3, true),

(3, 'SQL 집계 함수', '그룹별 통계를 구할 때 사용하는 SQL 구문은 GROUP BY와 _____ 이다.\nHAVING은 GROUP BY 이후의 조건을 필터링한다.', 'HAVING', 'WHERE은 그룹화 전 필터링, HAVING은 그룹화 후 필터링이다. 집계 함수(COUNT, SUM, AVG 등)와 함께 사용한다.', 'HAVING', 'WHERE', 'ORDER BY', 'DISTINCT', 'UNION', 2, true),

(3, '조인 종류', '한 테이블의 행이 다른 테이블의 여러 행과 매칭될 때 발생하는 조인을 _____ 조인이라고 한다.\n결과 행 수가 원래 테이블의 행 수보다 _____ 질 수 있다.', '카티전(카디션)', '카티전 조인은 매칭되는 행이 여러 개일 때 발생한다. 결과 집합이 곱셈적으로 증가할 수 있어 주의해야 한다.', '카티전(카디션)', '내부', '외부', '자체', '세미', 3, true);

-- ============================================
-- 소프트웨어공학 (14개)
-- ============================================
INSERT INTO subjective_problems (subject_id, question, question_text, answer, explanation, option1, option2, option3, option4, option5, difficulty, is_ai_generated) VALUES
(4, '소프트웨어 개발 모델', '요구사항이 명확하고 변경이 적은 경우 적합한 개발 모델은 _____ 이다.\n이 모델은 각 단계가 순차적으로 진행되며, 이전 단계로 돌아가기 어렵다.', '폭포수 모델', '폭포수(Waterfall) 모델은 요구사항 → 설계 → 구현 → 테스트 → 유지보수 순으로 진행한다. 문서화가 철저하지만 변경에 취약하다.', '폭포수 모델', '애자일', '프로토타입', '나선형', 'V-모델', 1, true),

(4, 'UML 다이어그램', 'UML에서 클래스 간의 관계를 나타내는 다이어그램은 _____ 다이어그램이다.\n이 다이어그램은 클래스, 속성, 메서드, 관계를 표현한다.', '클래스', '클래스 다이어그램은 정적 구조를 표현하며, 상속(일반화), 연관, 의존, 집계, 합성을 표현한다. 구조 다이어그램에 속한다.', '클래스', '객체', '순서', '상태', '액티비티', 1, true),

(4, '결합도와 응집도', '좋은 모듈 설계를 위해서는 결합도는 _____ , 응집도는 _____ 이어야 한다.\n기능 응집이 가장 높은 응집도 유형이다.', '낮게, 높게', '결합도는 모듈 간 의존도, 응집도는 모듈 내 요소들의 관련성이다. 낮은 결합도와 높은 응집도가 재사용성과 유지보수성을 높인다.', '낮게, 높게', '높게, 낮게', '낮게, 낮게', '높게, 높게', '상관없음', 2, true),

(4, '소프트웨어 테스트', '개발자가 작성한 코드의 내부 구조를 보고 테스트하는 방법을 _____ 테스트라고 한다.\n경로, 조건, 분기 커버리지 등이 이에 속한다.', '화이트박스', '화이트박스 테스트는 코드 구조를 알고 수행한다. 블랙박스 테스트는 요구사항 명세만 보고 테스트한다.', '화이트박스', '블랙박스', '그레이박스', '회귀', '인수', 1, true),

(4, '요구공학', '소프트웨어의 외부 행위를 명세하는 것을 _____ 요구사항이라고 한다.\n기능, 성능, 제약조건 등을 포함한다.', '기능', '기능 요구사항은 시스템이 무엇을 해야 하는지, 비기능 요구사항은 어떻게 수행해야 하는지(성능, 보안 등)를 정의한다.', '기능', '비기능', '도메인', '사용자', '시스템', 2, true),

(4, '형상 관리', '소스 코드의 변경 이력을 관리하고 버전 충돌을 방지하는 기법을 _____ 관리라고 한다.\nGit, SVN 등이 이에 속한다.', '형상', '형상 관리(Configuration Management)는 식별, 변경 통제, 상태 기록, 감사로 구성된다. 브랜치와 병합도 포함한다.', '형상', '품질', '위험', '일정', '원가', 1, true),

(4, '객체지향 설계', '객체지향의 3대 특성으로 캡슐화, 상속, _____ 이 있다.\n같은 메시지라도 객체별로 다른 방식으로 처리할 수 있게 한다.', '다형성', '다형성(Polymorphism)은 오버라이딩(상속)과 오버로딩(메서드 이름 동일, 매개변수 다름)으로 구현한다.', '다형성', '추상화', '캡슐화', '상속', '메시지전달', 1, true),

(4, '소프트웨어 품질 모델', 'ISO/IEC 25010 소프트웨어 품질 모델의 8가지 특성 중 _____ 은(는) 소프트웨어가 정상적으로 작동할 수 있는 정도이다.\n기능적합성, 성능 효율성, 호환성 등을 포함한다.', '기능 적합성', 'ISO 25010은 8가지 제품 품질 특성: 기능 적합성, 성능 효율성, 호환성, 사용성, 신뢰성, 보안성, 유지보수성, 이식성을 정의한다.', '기능 적합성', '신뢰성', '사용성', '효율성', '보안성', 3, true),

(4, '설계 패턴', '싱글턴 패턴은 특정 클래스의 인스턴스가 _____ 개만 생성되도록 보장하는 생성 패턴이다.\n전역 접근점을 제공하여 어디서든 동일한 인스턴스를 사용한다.', '1', '싱글턴은 private 생성자, static 인스턴스 변수, static getInstance() 메서드로 구현한다. 전역 상태 관리에 유용하다.', '1', '2', '3', '무제한', '실행 시 결정', 2, true),

(4, '애자일 방법론', '반복적이고 점진적인 개발을 강조하는 방법론은 _____ 이다.\n스프린트, 데일리 스크럼, 프로덕트 백로그 등의 개념을 사용한다.', '스크럼', '스크럼은 Product Owner, Scrum Master, 개발 팀으로 구성된다. 2~4주 스프린트로increment를 생산한다.', '스크럼', '폭포수', 'XP', 'FDD', 'RUP', 2, true),

(4, '사용자 인터페이스', '사용자 편의성을 평가하는 척도로 Nielsen의 _____ 가지 발견적 평가 항목이 있다.\n시스템 상태 가시성, 사용자 제어 및 자유 등이 이에 속한다.', '10', 'Nielsen의 10가지 휴리스틱: 시스템 상태 가시성, 현실 세계와의 일치, 사용자 제어, 일관성, 오류 방지, 기억 부하 최소화, 효율성, 심미성, 오류 복구, 도움말이다.', '10', '5', '7', '8', '12', 3, true),

(4, '소프트웨어 측정', '소프트웨어 규모를 측정하는 단위로 코드 라인 수를 의미하는 _____ 이 있다.\n이 측정 방법은 간단하지만 언어별 차이, 주석 포함 여부 등 문제가 있다.', 'LOC', 'LOC(Line of Code)는 가장 간단한 규모 측정법이다. 함수점(FP)은 기능 중심의 규모 측정법으로 더 정확하다.', 'LOC', 'FP', 'COCOMO', ' McCabe', 'HAL', 2, true),

(4, '유지보수 유형', '기존 기능을 변경하지 않고 코드 구조를 개선하는 유지보수를 _____ 유지보수라고 한다.\n가독성 향상, 중복 제거, 성능 최적화 등이 이에 속한다.', '완전', '완전(Perfective) 유지보수는 기능 추가가 아닌 내부 품질 향상이다. 적응(Adaptive)은 환경 변화 대응, 수정(Corrective)은 오류 수정이다.', '완전', '적응', '수정', '예방', '기능', 3, true),

(4, '아키텍처 패턴', 'MVC 패턴에서 Model은 데이터를, View는 화면을, _____ 은(는) 사용자 입력을 처리한다.\n이 패턴은 관심사의 분리를 실현한다.', 'Controller', 'MVC는 Model(비즈니스 로직/데이터), View(표현), Controller(입력 제어)로 구성된다. 웹 애플리케이션의 기본 패턴이다.', 'Controller', 'Service', 'Repository', 'DTO', 'Interceptor', 1, true);

-- ============================================
-- 정보보안 (14개)
-- ============================================
INSERT INTO subjective_problems (subject_id, question, question_text, answer, explanation, option1, option2, option3, option4, option5, difficulty, is_ai_generated) VALUES
(5, 'CIA 트라이어드', '정보보안의 3대 요소인 CIA는 기밀성, _____ , 가용성이다.\n이 중 무결성은 데이터가 변조되지 않았음을 보장한다.', '무결성', 'CIA Triad: Confidentiality(인가된 사용자만 접근), Integrity(데이터 변조 방지), Availability(필요 시 사용 가능). 정보보안의 핵심 개념이다.', '무결성', '인증', '인가', '추적성', '부인방지', 1, true),

(5, '대칭키 암호', '암호화와 복호화에 같은 키를 사용하는 방식을 _____ 암호라고 한다.\nAES, DES, 3DES 등이 이에 속한다.', '대칭키', '대칭키 암호는 속도가 빠르지만 키 배포 문제가 있다. 비대칭키(RSA, ECC)는 공개키/개인키 쌍을 사용하며 키 배포가 안전하다.', '대칭키', '비대칭키', '해시', '일방향', '양방향', 1, true),

(5, '해시 함수', '임의 길이의 데이터를 고정 길이의 값으로 변환하는 함수를 _____ 함수라고 한다.\n이 함수는 역변환이 불가능하며, MD5, SHA-256 등이 있다.', '해시', '해시 함수는 충돌 저항성, 역상 저항성, 제2역상 저항성을 만족해야 한다. 비밀번호 저장에 사용된다.', '해시', '암호화', '복호화', '서명', '인증', 2, true),

(5, '디지털 서명', '메시지의 송신자를 확인하고 무결성을 보장하는 기술을 _____ 서명이라고 한다.\n발신자의 _____ 키로 서명하고 수신자는 공개키로 검증한다.', '디지털', '디지털 서명은 해시값을 발신자의 개인키로 암호화한다. 수신자는 발신자의 공개키로 복호화하여 해시값을 비교한다.', '디지털', '전자', '공개키', '비밀키', '대칭키', 2, true),

(5, '방화벽', '내부 네트워크와 외부 네트워크 사이의 트래픽을 제어하는 장비를 _____ 라고 한다.\n패킷 필터링, 상태 검사, _____ 등의 유형이 있다.', '방화벽', '방화벽은 ACL 기반으로 트래픽을 허용/차단한다. NGFW(차세대 방화벽)는 응용 프로그램 수준까지 제어한다.', '방화벽', '라우터', '스위치', 'IDS', 'IPS', 1, true),

(5, '침입 탐지 시스템', '네트워크 침입 시도를 탐지하고 관리자에게 알리는 시스템을 _____ 라고 한다.\n이 시스템은 이상 탐지, 오용 탐지 등의 방법으로 공격을 식별한다.', 'IDS', 'IDS(Intrusion Detection System)는 모니터링과 경고가 주 목적이며, IPS는 실시간 차단까지 수행한다.', 'IDS', 'IPS', '방화벽', 'VPN', 'WAF', 2, true),

(5, 'SQL 인젝션', '웹 애플리케이션의 입력값에 SQL 명령어를 삽입하여 비정상적인 쿼리를 실행하는 공격을 _____ 인젝션이라고 한다.\n이를 방지하기 위해 _____ 구문을 사용해야 한다.', 'SQL', 'SQL 인젝션은 '' OR 1=1 -- 등의 입력으로 WHERE절을 우회한다. PreparedStatement(파라미터라이즈드 쿼리)로 방지한다.', 'SQL', 'XSS', 'CSRF', '세션', '쿠키', 2, true),

(5, 'XSS 공격', '웹 페이지에 악성 _____ 을 삽입하여 다른 사용자의 정보를 탈취하는 공격을 XSS라고 한다.\n저장형, 반사형, _____ 유형으로 나뉜다.', '스크립트', 'XSS(Cross-Site Scripting)는 입력값을 그대로 출력할 때 발생한다. 입력값 검증과 출력 인코딩으로 방지한다.', '스크립트', 'SQL', 'HTML', 'CSS', '이미지', 2, true),

(5, 'SSL/TLS', '웹 통신을 암호화하는 프로토콜은 _____ 이다.\n이 프로토콜은 공개키와 대칭키를 결합하여 안전한 통신을 제공한다.', 'TLS', 'TLS(Transport Layer Security)는 핸드셰이크에서 공개키로 세션키를 교환하고, 이후 대칭키로 데이터를 암호화한다. SSL의 후속이다.', 'TLS', 'SSH', 'IPSec', 'SFTP', 'HTTPS', 2, true),

(5, '인증 방식', '사용자 ID와 비밀번호만으로 인증하는 방식을 _____ 인증이라고 한다.\n보안을 강화하기 위해 _____ 인증(MFA)을 사용하는 것이 권장된다.', '단일', 'MFA(Multi-Factor Authentication)는 지식(비밀번호), 소유(OTP), 생체(지문) 중 2가지 이상을 조합한다.', '단일', '다중', '생체', '토큰', '서명', 1, true),

(5, 'PKI', '공개키 기반 구조인 _____ 는 디지털 인증서를 통해 공개키의 신뢰성을 보장한다.\n이 구조에서 인증서는 CA(Certificate Authority)가 발급한다.', 'PKI', 'PKI(Public Key Infrastructure)는 인증서 발급, 관리, 폐기를 담당한다. X.509 인증서 표준을 사용한다.', 'PKI', 'VPN', 'IDS', 'IPS', 'WAF', 2, true),

(5, '버퍼 오버플로우', '프로그램이 할당된 버퍼보다 많은 데이터를写入하여 인접 메모리를 침범하는 취약점을 _____ 오버플로우라고 한다.\n이를 악용하여 _____ 코드를 실행할 수 있다.', '버퍼', '버퍼 오버플로우는 스택이나 힙에서 발생한다. 입력값 길이 검증과 Safe 함수 사용으로 방지한다.', '버퍼', '스택', '힙', '메모리', '레지스터', 2, true),

(5, 'DDoS 공격', '다수의 좀비 PC를 이용하여 특정 서버에 대량의 트래픽을 집중시키는 공격을 _____ 공격이라고 한다.\n이 공격은 서비스 _____ 을(를) 목표로 한다.', 'DDoS', 'DDoS(Distributed Denial of Service)는 분산된 공격원으로 서비스 불가능 상태를 만든다. SYN Flood, UDP Flood 등이 있다.', 'DDoS', 'DoS', 'XSS', 'SQL', '피싱', 2, true),

(5, '접근 통제 모델', '사용자의 보안 등급과 자료의 보안 등급에 따라 접근을 제어하는 모델을 _____ 접근 통제라고 한다.\n군사 조직에서 주로 사용되며, Bell-LaPadula 모델이 이에 속한다.', '강제', '강제 접근 통제(MAC)는 시스템이 접근을 강제하며, 임의 접근 통제(DAC)는 소유자가 권한을 부여한다.', '강제', '임의', '역할', '규칙', '속성', 3, true);

-- ============================================
-- 애플리케이션테스트 (15개)
-- ============================================
INSERT INTO subjective_problems (subject_id, question, question_text, answer, explanation, option1, option2, option3, option4, option5, difficulty, is_ai_generated) VALUES
(6, '테스트 레벨', '개발 단위에 따른 테스트 레벨은 단위 테스트, 통합 테스트, 시스템 테스트, _____ 테스트 순이다.\n가장 마지막 단계에서 사용자 환경과 유사하게 테스트한다.', '인수', '인수 테스트(Acceptance Test)는 사용자 요구사항 충족 여부를 확인한다. α 테스트(개발 환경), β 테스트(실 사용자 환경)로 나뉜다.', '인수', '회귀', '기능', '성능', '보안', 1, true),

(6, '테스트 케이스 설계', '입력값의 유효한 경계와 무효한 경계를 찾는 기법을 _____ 경계값 분석이라고 한다.\n이 기법은 경계 근처에서 결함이 자주 발견된다는 경험에 기반한다.', '경계값', '경계값 분석은 최소, 최소+1, 보통, 최대-1, 최대 값을 테스트한다. 동일 클래스 분할과 함께 사용한다.', '경계값', '동일클래스', '상태전이', '원인결과', '에러추측', 2, true),

(6, '블랙박스 테스트', '내부 코드를 보지 않고 요구사항만으로 테스트하는 방법을 _____ 테스트라고 한다.\n동일 클래스 분할, 경계값 분석, 상태 전이 다이어그램 등을 사용한다.', '블랙박스', '블랙박스 테스트는 기능 중심 테스트로, 입력과 출력만 보고 검증한다. 화이트박스 테스트는 코드 구조를 보고 경로, 조건 등을 검증한다.', '블랙박스', '화이트박스', '회귀', '단위', '통합', 1, true),

(6, '화이트박스 테스트', '코드의 논리적 구조를 기반으로 테스트하는 방법을 _____ 테스트라고 한다.\n경로 커버리지, 분기 커버리지, 조건 커버리지 등이 있다.', '화이트박스', '화이트박스 테스트는 구조적 테스트로, 코드 커버리지를 측정한다. 문장 > 분기 > 조건 > 경로 순으로 엄격하다.', '화이트박스', '블랙박스', '기능', '인수', '시스템', 1, true),

(6, '테스트 커버리지', '모든 가능한 실행 경로를 테스트하는 것을 _____ 커버리지라고 한다.\n이 커버리지는 가장 엄격하지만, 루프가 있으면 테스트 케이스가 폭발적으로 증가한다.', '경로', '경로 커버리지는 모든 실행 경로를 1회 이상 실행한다. 분기 커버리지는 모든 분기 참/거짓을 1회 이상, 조건 커버리지는 각 조건의 참/거짓을 1회 이상 테스트한다.', '경로', '분기', '조건', '문장', 'MC/DC', 2, true),

(6, '상태 전이 테스트', '시스템의 상태 변화를 모델링하여 테스트하는 기법을 _____ 전이 테스트라고 한다.\n상태, 이벤트, 전이, 액션을 다이어그램으로 표현한다.', '상태', '상태 전이 다이어그램(STD)은 유한 상태 머신을 기반으로 한다. 유효 전이와 무효 전이를 모두 테스트한다.', '상태', '원인결과', '동일클래스', '경계값', '페어', 2, true),

(6, '성능 테스트', '시스템이 예상되는 부하에서 요구되는 성능을 만족하는지 확인하는 테스트를 _____ 테스트라고 한다.\n응답 시간, 처리량, 자원 사용률 등을 측정한다.', '성능', '성능 테스트는 부하 테스트(정상 부하), 스트레스 테스트(한계 부하), 안정성 테스트(장시간), 스파이크 테스트(급증)로 나뉜다.', '성능', '기능', '보안', '사용성', '호환성', 2, true),

(6, '회귀 테스트', '코드 수정 후 기존 기능이 손상되지 않았는지 재확인하는 테스트를 _____ 테스트라고 한다.\n자동화 도구를 사용하여 효율적으로 수행한다.', '회귀', '회귀 테스트는 변경된 부분과 영향받는 부분을 집중 테스트한다. CI/CD 파이프라인에 통합하여 자동화한다.', '회귀', '단위', '통합', '인수', '스모크', 1, true),

(6, '결함 관리', '테스트 중 발견된 결함의 수명 주기는 발견 → _____ → 수정 → 재테스트 → 종료이다.\n이 과정에서 결함의 우선순위와 심각도를 분류한다.', '등록', '결함 트래킹 시스템(Bugzilla, JIRA)에서 결함 상태를 관리한다. 재오픈, 연기, 중복 등의 상태도 있다.', '등록', '분류', '할당', '분석', '우선순위', 2, true),

(6, '동일 클래스 분할', '입력 도메인을 동일한 동작을 보이는 그룹으로 나누는 기법을 _____ 분할이라고 한다.\n각 그룹에서 대표값 하나를 선택하여 테스트한다.', '동일클래스', '동일 클래스 분할(Equivalence Partitioning)은 유효 클래스와 무효 클래스로 나눈다. 경계값 분석과 보완적으로 사용한다.', '동일클래스', '경계값', '상태전이', '원인결과', '결정표', 2, true),

(6, '사용성 테스트', '사용자가 시스템을 쉽게 사용할 수 있는지 평가하는 테스트를 _____ 테스트라고 한다.\nNielsen의 발견적 평가가 대표적인 평가 방법이다.', '사용성', '사용성 테스트는 학습성, 효율성, 기억성, 오류, 만족도를 평가한다. 사용자 관찰, 설문조사, 휴리스틱 평가를 사용한다.', '사용성', '기능', '성능', '호환성', '접근성', 1, true),

(6, '테스트 계획', '테스트 활동의 범위, 방법, 자원, 일정을 정의하는 문서를 테스트 _____ 라고 한다.\n이 문서에는 테스트 대상, 제외 항목, 완료 기준이 포함된다.', '계획서', '테스트 계획서는 테스트 정책, 전략, 일정, 자원, 위험을 포함한다. IEEE 829 표준 양식을 따른다.', '계획서', '명세서', '케이스', '결과서', '보고서', 2, true),

(6, '무작위 테스트', '예상치 못한 입력으로 시스템을 테스트하는 기법을 _____ 테스트라고 한다.\n이 테스트는 무작위 데이터, 잘못된 형식, 극단값 등을 사용한다.', '무작위', '무작위 테스트(Random/Monkey Testing)는 자동화 도구나 스크립트로 무작위 입력을 생성한다. 예외 상황에서 강건성을 검증한다.', '무작위', '스모크', '새니티', '탐색', '애드혹', 3, true),

(6, 'API 테스트', '웹 서비스의 API가 명세대로 동작하는지 검증하는 테스트를 _____ 테스트라고 한다.\nREST, SOAP, GraphQL 등의 프로토콜을 사용한다.', 'API', 'API 테스트는 Postman, SoapUI 등 도구로 수행한다. 요청/응답, 상태 코드, 헤더, 인증을 검증한다.', 'API', 'UI', '단위', '통합', '성능', 2, true),

(6, '테스트 자동화', '반복적인 테스트 작업을 도구로 자동 수행하는 것을 테스트 _____ 라고 한다.\nSelenium, Appium, JUnit 등이 대표적인 도구이다.', '자동화', '테스트 자동화는 초기 투자 비용이 크지만 장기적으로 효율적이다. CI/CD와 결합하여 회귀 테스트에 효과적이다.', '자동화', '수동화', '반자동화', '시뮬레이션', '모델링', 1, true);

-- ============================================
-- 프로그래밍언어 (14개)
-- ============================================
INSERT INTO subjective_problems (subject_id, question, question_text, answer, explanation, option1, option2, option3, option4, option5, difficulty, is_ai_generated) VALUES
(7, '프로그래밍 패러다임', '객체의 상태와 행위를 캡슐화하여 프로그래밍하는 방식을 _____ 지향 프로그래밍이라고 한다.\n클래스와 인스턴스 개념을 사용한다.', '객체', '객체지향 프로그래밍(OOP)은 캡슐화, 상속, 다형성, 추상화를 지원한다. Java, C++, Python 등이 지원한다.', '객체', '절차', '함수형', '논리', '선언형', 1, true),

(7, '변수 스코프', '함수 내부에서만 접근 가능한 변수를 _____ 변수라고 한다.\n반면 함수 외부에서 선언된 변수는 전역 변수이다.', '지역', '지역 변수(Local Variable)는 함수가 종료되면 소멸된다. 전역 변수(Global Variable)는 프로그램 전체에서 접근 가능하다.', '지역', '전역', '정적', '매개', '인스턴스', 1, true),

(7, '자료형', '정수를 저장하는 자료형으로 4바이트 크기의 _____ 이 있다.\n더 큰 정수는 long, 더 작은 정수는 short를 사용한다.', 'int', 'int는 일반적으로 32비트(4바이트)로 -2^31 ~ 2^31-1 범위를 표현한다. 부호 있는 정수(signed)와 부호 없는 정수(unsigned)로 나뉜다.', 'int', 'char', 'float', 'double', 'boolean', 1, true),

(7, '제어 구조', '조건에 따라 다른 명령을 실행하는 제어 구조는 _____ 문이라고 한다.\nif-else, switch-case 등이 이에 속한다.', '분기', '분기문은 조건의 참/거짓에 따라 실행 경로를 분기한다. 중첩 if, 다중 if-else, switch 등으로 확장할 수 있다.', '분기', '반복', '순차', '점프', '함수', 1, true),

(7, '함수와 메서드', '반복적으로 사용되는 코드 블록을 _____ 라고 한다.\n매개변수를 입력받고 반환값을 출력할 수 있다.', '함수', '함수(Function)는 재사용 가능한 코드 단위다. 메서드(Method)는 클래스에 속한 함수를 의미한다. 재귀 호출도 가능하다.', '함수', '변수', '클래스', '객체', '모듈', 1, true),

(7, '상속', '기존 클래스의 속성과 메서드를 새 클래스가 물려받는 개념을 _____ 이라고 한다.\n코드 재사용과 계층적 분류를 가능하게 한다.', '상속', '상속(Inheritance)은 부모 클래스의 특성을 자식 클래스가 물려받는다. Java는 단일 상속, Python은 다중 상속을 지원한다.', '상속', '캡슐화', '다형성', '추상화', '구현', 2, true),

(7, '다형성', '같은 이름의 메서드가 객체 유형에 따라 다르게 동작하는 특성을 _____ 이라고 한다.\n오버로딩과 오버라이딩으로 구현된다.', '다형성', '다형성(Polymorphism)은 "여러 형태"를 의미한다. 오버로딩(매개변수 다름), 오버라이딩(재정의)이 대표적 형태다.', '다형성', '상속', '캡슐화', '추상화', '메시지', 2, true),

(7, '예외 처리', '프로그램 실행 중 발생하는 오류를 안전하게 처리하는 구조를 _____ 처리라고 한다.\ntry-catch-finally 구문을 사용한다.', '예외', '예외(Exception)는 실행 중 오류다. 예외 처리는 프로그램 비정상 종료를 방지하고 적절한 오류 메시지를 제공한다.', '예외', '오류', '경고', '디버그', '로그', 1, true),

(7, '포인터와 참조', 'C/C++에서 메모리 주소를 저장하는 변수를 _____ 라고 한다.\n이 변수는 * 연산자로 선언하고, & 연산자로 주소를 얻는다.', '포인터', '포인터는 메모리 주소를 다루는 변수다. 동적 메모리 할당, 배열, 문자열 처리에 필수적이다. NULL 포인터는 유효하지 않은 주소다.', '포인터', '참조', '배열', '구조체', '共用체', 2, true),

(7, '재귀 함수', '자기 자신을 호출하는 함수를 _____ 함수라고 한다.\n이 함수는 반드시 종료 조건을 가져야 무한 루프를 방지할 수 있다.', '재귀', '재귀(Recursion) 함수는 Base Case(종료 조건)와 Recursive Case(재귀 호출)로 구성된다. 스택을 사용하여 구현된다.', '재귀', '반복', '중첩', '람다', '콜백', 2, true),

(7, '인터페이스', '클래스가 구현해야 하는 메서드의 시그니처만 정의한 것을 _____ 라고 한다.\n자바 8부터 default 메서드를 지원하기 시작했다.', '인터페이스', '인터페이스는 추상 메서드의 집합이다. 구현 클래스는 모든 메서드를 구현해야 한다. 다중 구현이 가능하다.', '인터페이스', '추상클래스', '클래스', '열거형', '어노테이션', 2, true),

(7, '람다 표현식', '이름 없는 익명 함수를 _____ 표현식이라고 한다.\n(매개변수) -> {실행 코드} 형식으로 작성한다.', '람다', '람다(Lambda)는 함수형 프로그래밍의 핵심이다. Java 8, Python, C# 등에서 지원한다. 고차 함수의 인자로 전달 가능하다.', '람다', '클로저', '콜백', '델리게이트', '프록시', 3, true),

(7, '제네릭', '데이터 유형을 일반화하여 재사용 가능한 코드를 작성하는 기법을 _____ 라고 한다.\nJava에서는 <T> 형식으로 사용한다.', '제네릭', '제네릭(Generic)은 유형 매개변수로 타입 안전성을 보장한다. 컴파일 시 유형 검사를 수행하여 런타임 오류를 방지한다.', '제네릭', '상속', '다형성', '캡슐화', '추상화', 3, true),

(7, '컴파일과 인터프리터', '소스 코드를 한 번에 기계어로 변환하는 방식을 _____ 라고 한다.\n반면 한 줄씩 실행하는 방식은 인터프리터이다.', '컴파일', '컴파일러(C, C++, Java)는 실행 파일(.exe, .class)을 생성한다. 인터프리터(Python, JavaScript, PHP)는 실행 시 번역한다.', '컴파일', '인터프리터', '어셈블러', '링커', '로더', 1, true);

-- 나머지 2개 추가 (운영체제, 네트워크 각 1개씩)
INSERT INTO subjective_problems (subject_id, question, question_text, answer, explanation, option1, option2, option3, option4, option5, difficulty, is_ai_generated) VALUES
(1, 'RAID 레벨', '데이터 중복 없이 스트라이핑만 수행하여 성능을 향상시키는 RAID 레벨은 _____ 이다.\n디스크 하나가 고장나면 모든 데이터를 잃는다.', 'RAID 0', 'RAID 0은 스트라이핑으로 읽기/쓰기 성능을 높이지만 장애 허용이 없다. RAID 1은 미러링, RAID 5는 패리티로 장애를 허용한다.', 'RAID 0', 'RAID 1', 'RAID 5', 'RAID 6', 'RAID 10', 3, true),

(2, 'ICMP 프로토콜', '네트워크 장비 간 오류 메시지 및 제어 메시지를 전달하는 프로토콜은 _____ 이다.\nping 명령어가 이 프로토콜을 사용하여 연결성을 테스트한다.', 'ICMP', 'ICMP(Internet Control Message Protocol)는 IP 계층의 보조 프로토콜이다. Destination Unreachable, Time Exceeded 등의 메시지를 보낸다.', 'ICMP', 'IGMP', 'ARP', 'RARP', 'DHCP', 2, true);
